module watchdog_timer (
    input clk,
    input rst,
    input enable,
    input [3:0] timeout, // 4-bit timeout value
    output reg timeout_expired
);
    reg [3:0] obf_count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_count <= 4'b0000;
            timeout_expired <= 1'b0;
        end else if (enable) begin
            if (obf_count < timeout) begin
                obf_count <= obf_count + 1;
                timeout_expired <= 1'b0;
            end else begin
                timeout_expired <= 1'b1; // Timeout has expired
            end
        end else begin
            obf_count <= 4'b0000; // Reset obf_count if not enabled
            timeout_expired <= 1'b0;
        end
    end
endmodule
